namespace TLOT
{
	enum class LogLevel {
		Info,
		Warning,
		Error,
		Critical
	};

	class Logger {
	public:
		// Utilisation de std::format_string pour valider la chaîne à la compilation
		template<typename... Args>
		static void log(LogLevel level, std::format_string<Args...> fmt, Args&&... args) {
			auto now = std::chrono::system_clock::now();
			std::string message = std::format(fmt, std::forward<Args>(args)...);
			
			std::lock_guard lock(mutex_);
			
			std::print("[{:%H:%M:%S}] [{}] {}\n", now, level_to_string(level), message);
		}

		// Version "Smart" qui capture le fichier et la ligne automatiquement
		template<typename... Args>
		static void debug(std::format_string<Args...> fmt, Args&&... args, 
						std::source_location loc = std::source_location::current()) {
			
			std::lock_guard lock(mutex_);
			std::print(std::cerr, "DEBUG: {} ({}:{}) -> {}\n", 
					loc.function_name(), loc.file_name(), loc.line(),
					std::format(fmt, std::forward<Args>(args)...));
		}

		static void panic(std::string_view msg) {
			std::lock_guard lock(mutex_);
			std::print(std::cerr, "PANIC: {}\nStacktrace:\n{}\n", msg, std::stacktrace::current());
		}

	private:
		static inline std::mutex mutex_;

		static constexpr std::string_view level_to_string(LogLevel level) {
			switch (level) {
				case LogLevel::Info:     return "INFO";
				case LogLevel::Warning:  return "WARNING";
				case LogLevel::Error:    return "ERROR";
				case LogLevel::Critical: return "CRITICAL";
				default:                 return "UNKNOWN";
			}
		}
	};
}